import React from 'react';
import Modal from './Modal';

const InfoRow = ({ icon, label, value }) => (
  <div className="profile-info-row">
    {icon && <i className={`bi ${icon}`} style={{ color: 'var(--primary)', width: 16, flexShrink: 0 }} />}
    <span className="profile-info-label">{label}</span>
    <span className="profile-info-value">{value || <span style={{ color: 'var(--text-light)' }}>—</span>}</span>
  </div>
);

export default function DoctorViewModal({ open, onClose, doctor, onEdit }) {
  if (!doctor) return null;

  const initials = doctor.name?.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2);

  return (
    <Modal
      open={open}
      onClose={onClose}
      title="Doctor Profile"
      size="md"
      footer={
        <div className="d-flex justify-content-end gap-2">
          <button className="btn btn-sm btn-outline-secondary" onClick={onClose}>Close</button>
          <button className="btn btn-sm btn-primary" onClick={() => { onClose(); onEdit(doctor); }}>
            <i className="bi bi-pencil me-1" />Edit Profile
          </button>
        </div>
      }
    >
      {/* Banner */}
      <div
        className="d-flex align-items-center gap-3 p-3 rounded-3 mb-4"
        style={{ background: 'linear-gradient(135deg, #e8f1ff, #e0faf5)' }}
      >
        <div
          style={{
            width: 64, height: 64, borderRadius: '50%', flexShrink: 0,
            background: 'linear-gradient(135deg, var(--primary), var(--secondary))',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            color: '#fff', fontSize: '1.4rem', fontWeight: 700,
            boxShadow: '0 4px 12px rgba(42,127,255,0.3)',
          }}
        >
          {initials}
        </div>
        <div>
          <div style={{ fontWeight: 700, fontSize: '1.1rem' }}>{doctor.name}</div>
          <div style={{ fontSize: '0.8125rem', color: 'var(--text-muted)' }}>{doctor.email}</div>
          <div className="d-flex gap-2 mt-1 flex-wrap">
            {doctor.specialization && (
              <span style={{ background: 'var(--primary-light)', color: 'var(--primary-dark)', fontSize: '0.72rem', fontWeight: 600, padding: '1px 8px', borderRadius: 99 }}>
                {doctor.specialization}
              </span>
            )}
            <span style={{ background: 'var(--secondary-light)', color: 'var(--secondary-dark)', fontSize: '0.72rem', fontWeight: 600, padding: '1px 8px', borderRadius: 99 }}>
              {doctor.role === 'admin' ? 'Admin / Doctor' : 'Doctor'}
            </span>
            {doctor.isActive === false && (
              <span style={{ background: '#fee2e2', color: '#991b1b', fontSize: '0.72rem', fontWeight: 600, padding: '1px 8px', borderRadius: 99 }}>
                Inactive
              </span>
            )}
          </div>
        </div>
      </div>

      <div className="row g-3">
        <div className="col-12">
          <div className="profile-section-card">
            <div className="profile-section-title">
              <i className="bi bi-person-badge me-2" style={{ color: 'var(--primary)' }} />Contact Information
            </div>
            <InfoRow label="Phone" value={doctor.phone} />
            <InfoRow label="Address" value={doctor.address} />
          </div>
        </div>
        <div className="col-12">
          <div className="profile-section-card">
            <div className="profile-section-title">
              <i className="bi bi-award me-2" style={{ color: 'var(--secondary-dark)' }} />Professional Details
            </div>
            <InfoRow label="Specialization" value={doctor.specialization} />
            <InfoRow label="License No." value={doctor.licenseNumber} />
            <InfoRow label="Experience" value={doctor.experience ? `${doctor.experience} years` : null} />
          </div>
        </div>
      </div>
    </Modal>
  );
}
